  const images = [
    "/image1.png",
    "/image2.png",
    "/image3.png",
    "/image4.png",
    "/image5.png",
  ];

  const scrollRef = useRef(null);

  // // Auto scroll logic
  useEffect(() => {
    const container = scrollRef.current;
    let scrollAmount = 0;

    const scroll = () => {
      if (!container) return;
      scrollAmount += 0.5;
      container.scrollLeft = scrollAmount;

      // reset for infinite effect
      if (scrollAmount >= container.scrollWidth / 2) {
        scrollAmount = 0;
      }
    };

    const interval = setInterval(scroll, 20);
    return () => clearInterval(interval);
  }, []);

  /* last section */
  const wrapRef = useRef(null);
  const leftImgRef = useRef(null);
  const rightImgRef = useRef(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      const items = wrapRef.current.children;
      gsap.from(items[0], {
        y: -80,
        opacity: 0,
        duration: 2,
        ease: "power3.out",
        scrollTrigger: { trigger: wrapRef.current, start: "top 80%" },
      });
      gsap.from(items[1], {
        x: -120,
        opacity: 0,
        duration: 2,
        ease: "power3.out",
        scrollTrigger: { trigger: wrapRef.current, start: "top 80%" },
      });
      gsap.from(items[2], {
        y: 80,
        opacity: 0,
        duration: 2,
        ease: "power3.out",
        scrollTrigger: { trigger: wrapRef.current, start: "top 80%" },
      });
      gsap.from(leftImgRef.current, {
        x: -200,
        opacity: 0,
        duration: 1,
        ease: "power3.out",
        scrollTrigger: { trigger: wrapRef.current, start: "top 80%" },
      });
      gsap.from(rightImgRef.current, {
        x: 200,
        opacity: 0,
        duration: 1,
        ease: "power3.out",
        scrollTrigger: { trigger: wrapRef.current, start: "top 80%" },
      });
      [leftImgRef.current, rightImgRef.current].forEach((el, i) => {
        gsap.to(el, {
          y: -20,
          duration: 2 + i * 0.3,
          repeat: -1,
          yoyo: true,
          ease: "sine.inOut",
        });
      });
    });
    return () => ctx.revert();
  }, []);

  /* fifth section */
  const textWrapRef = useRef(null);
  const circleRef = useRef(null);
  const s5BtnRef = useRef(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      const trigger = { trigger: textWrapRef.current, start: "top 80%" };

      // Circle - scale thi aave
      gsap.fromTo(
        circleRef.current,
        { scale: 0, opacity: 0 },
        {
          scale: 1,
          opacity: 1,
          duration: 1,
          ease: "expo.out",
          scrollTrigger: { trigger: circleRef.current, start: "top 85%" },
        },
      );

      // "Woman-owned business" - p tag
      gsap.from(textWrapRef.current.children[0], {
        scrollTrigger: trigger,
        y: -40,
        opacity: 0,
        duration: 0.7,
        ease: "power3.out",
      });

      // Heading - h2
      gsap.from(textWrapRef.current.children[1], {
        scrollTrigger: trigger,
        y: -50,
        opacity: 0,
        duration: 0.8,
        delay: 0.12,
        ease: "power3.out",
      });

      // Paragraph
      gsap.from(textWrapRef.current.children[2], {
        scrollTrigger: trigger,
        y: 40,
        opacity: 0,
        duration: 0.7,
        delay: 0.24,
        ease: "power3.out",
      });

      // Button - alag set + to sathe
      gsap.set(s5BtnRef.current, { opacity: 0, y: 30, scale: 0.85 });
      gsap.to(s5BtnRef.current, {
        scrollTrigger: trigger,
        opacity: 1,
        y: 0,
        scale: 1,
        duration: 0.7,
        delay: 0.38,
        ease: "back.out(1.7)",
      });
    });
    return () => ctx.revert();
  }, []);

  /* third section */
  const sec3ParaRef = useRef(null);
